var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"방금 터널 4분의 1지점을 지나쳤어요, 연화. 이제 병목 지점까지 그리 멀지 않아요.","JPN":"レンカさん、先ほどトンネルの4分の1地点を通過しました。もうすぐボトルネック地点です。","ENG":"We just passed the one-quarter point of the tunnel, Yeonhwa. The bottleneck isn't far now.","TWN":"剛剛已經通過隧道4分之1的位置了。蓮華，離瓶頸點不遠了。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...응. 이제 눈으로도 보여. 엄청 큰 괴물이 지키고 있네.","JPN":"……うん。もう肉眼でも見えるわ。すごく大きな化け物が守ってる。","ENG":"...Yeah. I can see it now. There's a huge monster guarding it.","TWN":"……嗯。我已經看到了，有個很大的怪物守在那裡。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"준비해둔 이터니움을 이미 절반쯤 쓴 것 같은데, 괜찮겠어요? 돌아올 때의 에너지도 생각하면...","JPN":"用意したエタニウムはすでに半分にまで減っているようですが、大丈夫なんですか？　戻る時のエネルギーも考慮しないと……","ENG":"It looks like you've already used about half of the Eternium we prepared. Will you be all right? Considering the energy you'll need to get back...","TWN":"你準備的永恆之金好像已經用掉一半了，真的沒問題嗎？也要考慮回程的能量。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"걱정 마. 병목 현상만 해결하면 들어온 입구로 알아서 튕겨져 나올 거라며?","JPN":"心配しないで。ボトルネック現象さえ解決されれば、入ってきた入口まで勝手に弾き飛ばされるのでしょう？","ENG":"Don't worry. If we just resolve the bottleneck, I'll be automatically pushed back out through the entrance I came in from, right?","TWN":"別擔心。只要解決瓶頸，我們就會被自動彈回入口。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"그건 이 작전이 성공했을 때의 얘기죠! 만에 하나라는 게 있는 거잖아요!","JPN":"それはこの作戦が成功した場合の話です！　万が一ということもあるじゃないですか！","ENG":"That's only if this operation succeeds! There's always the chance it won't!","TWN":"那是在作戰成功的情況下！萬一失敗呢！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...주한.","JPN":"……シスイ。","ENG":"...Joo Han.","TWN":"……周翰。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 만에 하나에, 우리의 미래가 걸려 있다면... 난 거기에 전부를 걸 거야.","JPN":"その万が一の事態に私たちの未来がかかっているなら……私はそれにすべてをかけるわ。","ENG":"If our future depends on that one chance... then I'll stake everything on it.","TWN":"如果那萬分之一關係到我們的未來……我會賭上一切。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"겪어본 적도 없는 미래가, 당신 목숨보다 소중하다고 어떻게 확신해요?","JPN":"経験したこともない未来が自分の命より大切だなんて、どうして信じられるんですか？","ENG":"How can you be sure a future you've never experienced is more important than your life?","TWN":"你怎麼確定從沒見過的未來，比你的命還重要？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"과거는 오늘만큼 소중히 여길 순 없겠지만... 미래는 내일의 오늘이니까.","JPN":"過去を今日ほどは大切に思えなくても……未来は明日の今日だから。","ENG":"The past may not be as precious as today... but the future is tomorrow's today.","TWN":"或許過去沒有今天重要……但未來是明天的今天。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"난...","JPN":"私は……","ENG":"I...","TWN":"我是……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내가 본 적 없는 오늘을 지키고 싶어.","JPN":"私が見たことのない今日を守りたいの。","ENG":"want to protect a today I've never seen.","TWN":"想守住我從未見過的今天。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"분명, 어제보다 소중한 풍경이 기다리고 있을 거라고 생각해.","JPN":"きっと、昨日より大切な風景が待っていると思うわ。","ENG":"I'm sure a view more precious than yesterday is waiting there.","TWN":"我相信，那裡一定有比昨天更珍貴的景象在等著我。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"뻔한 말은 하지 않을게요.","JPN":"綺麗事は言いません。","ENG":"I won't say anything obvious.","TWN":"我就不說那些老套的話了。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"보고 와요. 당신이 보고 싶은 풍경.","JPN":"見てきてください。あなたが見たい風景を。","ENG":"Go see it. The view you want to see.","TWN":"去看看你想看到的風景吧。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"신호가 미약합니다. 통신이 곧 끊어집니다.","JPN":"信号が弱いです。もうすぐ通信が途切れます。","ENG":"The signal is weakening. Comms will be cut off soon.","TWN":"訊號正在減弱，通訊即將中斷。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...고마워.","JPN":"……ありがとう。","ENG":"...Thank you.","TWN":"……謝謝。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"지금 갈게.","JPN":"今行くわ。","ENG":"I'm heading out now.","TWN":"我現在就去。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하아, 겨우 다 치웠다.","JPN":"はあ、やっと全部片付いた。","ENG":"Whew, that finally clears them out.","TWN":"呼，總算清理完了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 고장 난 깡통들, 지난 번에 와서 간신히 치워 놨는데 전부 멀쩡하게 돌아다녀서 혼났네요.","JPN":"この壊れたボロ缶たち、この前来た時にやっとの思いで片付けたのに、全部元通りになってて死ぬかと思いました。","ENG":"These broken tin cans. We barely cleared them out last time we were here, and they gave us a real hard time being all up and moving again.","TWN":"上次好不容易才清乾淨這些破爛鐵罐，結果現在又全部完好無缺地跑出來。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어쩔 수 없지. 그 지난 번은 미래고, 여긴 과거니까.","JPN":"仕方ないよ。その「この前」は未来で、ここは過去なんだから。","ENG":"It couldn't be helped. That last time was the future, and this is the past.","TWN":"沒辦法。那個上次是未來，這裡是過去。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"숨지 않는군.","JPN":"隠れないんだな。","ENG":"You're not hiding.","TWN":"你們沒有躲起來啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHADOW_EXILER_NPC_QM","text":{"KOREA":"여기까지 올 줄은 몰랐군요.","JPN":"ここまで来るとは思いませんでした。","ENG":"I didn't expect you to make it this far.","TWN":"沒想到你們真的能到這裡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...스완.","JPN":"……スワン。","ENG":"...Swan.","TWN":"……史旺。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"엑자일러 사냥꾼을 피해, 클리파의 틈새에 얌전히 숨어 있다고 생각했는데 말이죠.","JPN":"エグザイラーハンターの目を逃れ、クリファの狭間に大人しく隠れていましたのに。","ENG":"I thought I was quietly hiding in a gap within the Qlipha to avoid the Exile Hunters.","TWN":"我還以為你們會躲避流放者獵人，乖乖躲在逆卡巴拉的縫隙裡。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};